content:
{
  "sentences": [
    {
      "text": "我以前去過臺北的故宮。",
      "pinyin": "Wǒ yǐqián qù guò Táiběi de Gùgōng.",
      "pinyin_numeric": "wo3 yi3qian2 qu4 guo4 Tai2bei3 de Gu4gong1.",
      "translation_en": "I have been to the National Palace Museum in Taipei before.",
      "translation_ko": "저는 예전에 타이베이의 고궁에 가 본 적이 있습니다."
    },
    {
      "text": "你以前吃過臺灣的小吃嗎？",
      "pinyin": "Nǐ yǐqián chī guò Táiwān de xiǎochī ma?",
      "pinyin_numeric": "ni3 yi3qian2 chi1 guo4 Tai2wan1 de xiao3chi1 ma0?",
      "translation_en": "Have you ever eaten Taiwanese street food before?",
      "translation_ko": "예전에 대만의 길거리 음식을 먹어 본 적이 있나요?"
    },
    {
      "text": "我從來沒有去過國外旅行。",
      "pinyin": "Wǒ cónglái méiyǒu qù guò guówài lǚxíng.",
      "pinyin_numeric": "wo3 cong2lai2 mei2you3 qu4 guo4 guo2wai4 lü3xing2.",
      "translation_en": "I have never traveled abroad before.",
      "translation_ko": "저는 예전에 해외 여행을 가 본 적이 전혀 없습니다."
    },
    {
      "text": "他以前在臺中吃過很好吃的牛肉麵。",
      "pinyin": "Tā yǐqián zài Táizhōng chī guò hěn hǎochī de niúròumiàn.",
      "pinyin_numeric": "ta1 yi3qian2 zai4 Tai2zhong1 chi1 guo4 hen3 hao3chi1 de niu2rou4mian4.",
      "translation_en": "He has eaten very delicious beef noodles in Taichung before.",
      "translation_ko": "그는 예전에 타이중에서 아주 맛있는 소고기 국수를 먹어 본 적이 있습니다."
    },
    {
      "text": "我們以前去過墾丁的海邊，風景很漂亮。",
      "pinyin": "Wǒmen yǐqián qù guò Kěndīng de hǎibiān, fēngjǐng hěn piàoliang.",
      "pinyin_numeric": "wo3men yi3qian2 qu4 guo4 Ken3ding1 de hai3bian1, feng1jing3 hen3 piao4liang.",
      "translation_en": "We have been to the beach in Kenting before, and the scenery was very beautiful.",
      "translation_ko": "우리는 예전에 컨딩의 해변에 가 본 적이 있는데, 경치가 아주 아름다웠습니다."
    },
    {
      "text": "你以前喝過珍珠奶茶嗎？",
      "pinyin": "Nǐ yǐqián hē guò zhēnzhū nǎichá ma?",
      "pinyin_numeric": "ni3 yi3qian2 he1 guo4 zhen1zhu1 nai3cha2 ma0?",
      "translation_en": "Have you ever drunk bubble tea before?",
      "translation_ko": "예전에 버블티를 마셔 본 적이 있나요?"
    },
    {
      "text": "我聽過這首歌，可是沒有聽過這個版本。",
      "pinyin": "Wǒ tīng guò zhè shǒu gē, kěshì méiyǒu tīng guò zhège bǎnběn.",
      "pinyin_numeric": "wo3 ting1 guo4 zhe4 shou3 ge1, ke3shi4 mei2you3 ting1 guo4 zhe4ge ban3ben3.",
      "translation_en": "I have heard this song before, but I haven't heard this version.",
      "translation_ko": "저는 이 노래를 들어 본 적이 있지만, 이 버전은 들어 본 적이 없습니다."
    },
    {
      "text": "她以前學過中文，所以會說一點。",
      "pinyin": "Tā yǐqián xué guò Zhōngwén, suǒyǐ huì shuō yīdiǎn.",
      "pinyin_numeric": "ta1 yi3qian2 xue2 guo4 Zhong1wen2, suo3yi3 hui4 shuo1 yi1dian3.",
      "translation_en": "She has studied Chinese before, so she can speak a little.",
      "translation_ko": "그녀는 예전에 중국어를 배운 적이 있어서 조금 말할 수 있습니다."
    },
    {
      "text": "我第一次去淡水，覺得那裡很好玩。",
      "pinyin": "Wǒ dì yī cì qù Dànshuǐ, juéde nàlǐ hěn hǎowán.",
      "pinyin_numeric": "wo3 di4 yi1 ci4 qu4 Dan4shui3, jue2de na4li3 hen3 hao3wan2.",
      "translation_en": "It was my first time going to Tamsui, and I thought it was very fun there.",
      "translation_ko": "저는 처음으로 단수이에 가 봤는데, 거기가 아주 재미있다고 생각했습니다."
    },
    {
      "text": "你以前做過這個工作嗎？",
      "pinyin": "Nǐ yǐqián zuò guò zhège gōngzuò ma?",
      "pinyin_numeric": "ni3 yi3qian2 zuo4 guo4 zhe4ge gong1zuo4 ma0?",
      "translation_en": "Have you done this job before?",
      "translation_ko": "예전에 이 일을 해 본 적이 있나요?"
    }
  ]
}
